import React, { useEffect, useState } from 'react';

function App() {
  const [campaigns, setCampaigns] = useState([]);
  const [filters, setFilters] = useState({ id: '', name: '', status: '' });

  const fetchCampaigns = () => {
    const params = new URLSearchParams();
    if (filters.id) params.append('q', filters.id);
    if (filters.name) params.append('q', filters.name);
    if (filters.status) params.append('status', filters.status);

    // note: the backend 'q' param searches id or name
    fetch('/api/campaigns?' + params.toString())
      .then(res => res.json())
      .then(data => {
        if (data.success) setCampaigns(data.data);
      })
      .catch(console.error);
  };

  useEffect(() => {
    fetchCampaigns();
  }, [filters]);

  const handleChange = e => {
    const { name, value } = e.target;
    setFilters(f => ({ ...f, [name]: value }));
  };

  const clearFilters = () => setFilters({ id: '', name: '', status: '' });

  return (
    <div style={{ padding: 20 }}>
      <h1>Campaigns</h1>
      <div style={{ marginBottom: 20 }}>
        <label>
          ID:{' '}
          <input
            name="id"
            value={filters.id}
            onChange={handleChange}
            placeholder="search..."
          />
        </label>{' '}
        <label>
          Name:{' '}
          <input
            name="name"
            value={filters.name}
            onChange={handleChange}
            placeholder="search..."
          />
        </label>{' '}
        <label>
          Status:{' '}
          <select name="status" value={filters.status} onChange={handleChange}>
            <option value="">Any</option>
            <option value="1">Active</option>
            <option value="0">Paused</option>
          </select>
        </label>{' '}
        <button onClick={clearFilters}>Clear</button>
      </div>
      <ul>
        {campaigns.map(c => (
          <li key={c.id}>{c.name} (status: {c.status})</li>
        ))}
      </ul>
    </div>
  );
}

export default App;
